/**
 * Подтема StarDsTheme.Inverse
 */
@Composable
public fun StarDsTheme.Inverse(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalStarDsColors.current
    val overrideColors = currentColors.copyAttrs(InverseColorsOverride)
    val currentGradients = LocalStarDsGradients.current
    val overrideGradients = currentGradients.copyAttrs(InverseGradientsOverride)
    StarDsTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
